public async Task<Product> GetProductById(int id)
{
    _logger.LogInformation("Tentative de récupération du produit {ProductId}", id);
    try
    {
        var product = await _context.Products.FindAsync(id);
        if (product == null)
        {
            _logger.LogWarning("Produit {ProductId} non trouvé", id);
            throw new NotFoundException($"Produit {id} introuvable");
        }
        return product;
    }
    catch (SqlException ex)
    {
        _logger.LogError(ex, "Erreur base de données lors de la recherche du produit {ProductId}", id);
        throw new DatabaseException("Erreur technique", ex);
    }
}
